ize:13px;line-height:1.5}.course{padding:17px;border-radius:17px;background:#f7f9fd;margin-top:12px}.course-head{display:flex;justify-content:space-between;font-size:13px;font-weight:750}.bar{height:7px;background:#e2e8f2;border-radius:99px;margin-top:13px;overflow:hidden}.bar i{display:block;height:100%;border-radius:99px;background:linear-gradient(90deg,#2563eb,#7c3aed)}.bar.teal i{background:#14b8a6}.features{padding:78px 0 100px;border-top:1px solid #e5eaf2}.section-title{font-size:38px;letter-spacing:-1.7px;margin:0 0 12px}.grid{display:grid;grid-template-columns:repeat(3,1fr);gap:18px;margin-top:36px}.card{background:#fff;border:1px solid #e7ebf3;border-radius:20px;padding:25px}.icon{width:45px;height:45px;border-radius:13px;display:grid;place-items:center;background:#eaf1ff;color:#2563eb;font-weight:900;margin-bottom:22px}.card:nth-child(2) .icon{background:#e7faf7;color:#0d9488}.card:nth-child(3) .icon{background:#f1eafe;color:#7c3aed}.card h3{font-size:18px;margin:0 0 9px}.card p{color:#6a788d;line-height:1.6;font-size:14px;margin:0}.access{display:grid;grid-template-columns:repeat(3,1fr);gap:14px;margin-top:40px}.access a{padding:20px;border-radius:16px;color:white;font-weight:800;display:flex;justify-content:space-between;align-items:center}.admin{background:#1e40af}.instructor{background:#0d9488}.student{background:linear-gradient(135deg,#2563eb,#7c3aed)}@media(max-width:850px){.hero{grid-template-columns:1fr;padding-top:45px}.dashboard{transform:none}.grid,.access{grid-template-columns:1fr}h1{font-size:46px}.nav span{display:none}}
</style></head><body><div class="shell"><nav class="nav"><div class="brand">Aula<i>Pro</i></div><span>Plataforma integral de aprendizaje</span></nav><main class="hero"><section><div class="eyebrow"><span class="dot"></span> Aprende, avanza y certifícate</div><h1>Tu progreso abre el <em>siguiente paso.</em></h1><p class="lead">Cursos claros, evaluaciones con acompañamiento y certificados verificables. Una experiencia diseñada para que estudiantes e instructores sepan siempre qué sigue.</p><div class="actions"><a class="btn primary" href="/student">Entrar como estudiante →</a><a class="btn" href="#accesos">Ver todos los accesos</a></div></section><aside class="dashboard"><div class="top"><div class="mini-brand">Mi aprendizaje</div><div class="avatar"></div></div><div class="progress"><div class="ring"></div><div><h3>Vas por buen camino</h3><div class="muted">9 de 12 temas completados<br>Siguiente: Evaluación de liderazgo</div></div></div><div class="course"><div class="course-head"><span>Liderazgo de equipos</span><span>78%</span></div><div class="bar"><i style="width:78%"></i></div></div><div class="course"><div class="course-head"><span>Comunicación efectiva</span><span>52%</span></div><div class="bar teal"><i style="width:52%"></i></div></div></aside></main></div><section class="features"><div class="shell"><h2 class="section-title">Todo el recorrido, en un solo lugar.</h2><p class="lead">Tres experiencias especializadas que comparten la misma información y las mismas reglas.</p><div class="grid"><article class="card"><div class="icon">01</div><h3>Avance secuencial</h3><p>Cada evaluación calificada desbloquea el siguiente tema y actualiza el progreso automáticamente.</p></article><article class="card"><div class="icon">02</div><h3>Acompañamiento real</h3><p>El instructor revisa respuestas abiertas, entrega retroalimentación y concede intentos extra cuando se necesitan.</p></article><article class="card"><div class="icon">03</div><h3>Logros verificables</h3><p>Al completar el curso se emite un certificado profesional con código único y verificación QR.</p></article></div><div class="access" id="accesos"><a class="admin" href="/admin"><span>Administración</span><span>→</span></a><a class="instructor" href="/instructor"><span>Instructor</span><span>→</span></a><a class="student" href="/student"><span>Estudiante</span><span>→</span></a></div></div></section></body></html>
